/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{

    LedgerJournalTable     ledgerJournalTable;
    LedgerJournalTrans     ledgerJournalTrans;
    SrsReportRunController reportRunController;
    SrsReportRunImpl       srsReportRun;
    ETGCreditNoteContract dataContract;

    if(_args.record() && _args.dataset() == tableNum(LedgerJournalTable))
    {
        ledgerJournalTable = _args.record();
    }
    else if(_args.record() && _args.dataset() == tableNum(LedgerJournalTrans))
    {
        ledgerJournalTrans = _args.record();
        ledgerJournalTable = ledgerJournalTrans.ledgerJournalTable();
    }
    else
    {
        throw Error(Error::missingFormActiveBuffer(formStr(LedgerJournalTransDaily)));
    }


    reportRunController = new SrsReportRunController();
    dataContract = new   ETGCreditNoteContract();
    reportRunController.parmReportName(ssrsReportStr(ETGCreditNoteReport, ETGDebitNotePl));
    reportRunController.parmShowDialog(false);
    dataContract = reportRunController.parmReportContract().parmRdpContract() as ETGCreditNoteContract;
    dataContract.parmJournalNum(ledgerJournalTable.JournalNum);
    srsReportRun = reportRunController.parmReportRun() as SrsReportRunImpl;
    reportRunController.parmShowDialog(false);
    reportRunController.parmReportRun(srsReportRun);
    reportRunController.parmReportContract().parmPrintSettings().printMediumType(SRSPrintMediumType::Screen);
    reportRunController.startOperation();
}
